          endif;

        logMsg(%trim(qJob.nbr)  + '/' +
        %trim(qJob.user) + '/' +
        %trim(qJob.name) + ' count#: ' + %char(count));

      hasJob = f_getNextJob(hJobs: jobl0100);
      enddo;

      f_cloJobLst(hJobs);
      endif;

end-proc;

**free
