//       >>PARM<< TRUNCNBR(*NO);                                       *
//       >>PARM<< DBGVIEW(*LIST);                                      *
//       >>PARM<< TGTRLS(V7R3M0  );                                    *
//       >>PARM<< OPTION(*EVENTF);                                     *
