  lineNbr char(10) dim(10);
end-ds;

dcl-c JOBLOG_MAX_MSG_TEXT_LEN 132;
dcl-c JOBLOG_MAX_MSG_HELP_LEN 3000;

/copy QBASICS1,PBASICS1                     Tools/400 Runtime Library
